const config = $input.first().json;
const mappings = config.mappings || [];
const jobs = [];

for (const mapping of mappings) {
  jobs.push({
    json: {
      name: mapping.name,
      source: mapping.source,
      destination: mapping.destination,
      fields: mapping.fields,
      sync_direction: mapping.sync_direction,
      sync_key: mapping.sync_key || null,
      conflict_resolution: mapping.conflict_resolution || 'latest_wins',
      batch_size: config.global_settings.batch_size,
      started_at: new Date().toISOString()
    }
  });
}

return jobs;

const items = $input.all();
const mapping = items[0].json;
const records = items.slice(1);
const fieldMap = mapping.fields;
const transformedRecords = [];

for (const record of records) {
  const transformed = {};
  for (const fieldMapping of fieldMap) {
    let value = record.json[fieldMapping.source];

    switch (fieldMapping.transform) {
      case 'lowercase':
        value = typeof value === 'string' ? value.toLowerCase() : value;
        break;
      case 'uppercase':
        value = typeof value === 'string' ? value.toUpperCase() : value;
        break;
      case 'capitalize':
        value = typeof value === 'string' ? value.charAt(0).toUpperCase() + value.slice(1) : value;
        break;
      case 'date_format':
        value = value ? new Date(value).toISOString().split('T')[0] : value;
        break;
      case 'integer':
        value = parseInt(value, 10);
        break;
      case 'decimal':
        value = parseFloat(value);
        break;
      case 'currency':
        value = typeof value === 'number' ? `$${value.toFixed(2)}` : value;
        break;
      case 'join':
        value = Array.isArray(value) ? value.join(fieldMapping.delimiter || ', ') : value;
        break;
      case 'map':
        value = fieldMapping.map && fieldMapping.map[value] ? fieldMapping.map[value] : value;
        break;
      case 'json_stringify':
        value = typeof value === 'object' ? JSON.stringify(value) : value;
        break;
      default:
        break;
    }

    transformed[fieldMapping.destination] = value;
  }
  transformedRecords.push({ json: transformed });
}

return transformedRecords;

const items = $input.all();
const totalSynced = items.length;
const jobName = items[0]?.json?.sync_job || 'unknown';
const completedAt = new Date().toISOString();

return [{
  json: {
    summary: `Sync completed: ${totalSynced} records processed`,
    job_name: jobName,
    records_synced: totalSynced,
    completed_at: completedAt,
    status: 'success'
  }
}];

